/**
 * decisionDoctrine.ts
 *
 * Centralized Universal Decision Doctrine for the ACTD Drill Engine.
 *
 * This module defines the five core principles that govern every drill option,
 * outcome, label, and expert reasoning generated by the system.
 *
 * IMPORTANT: This doctrine does NOT replace ACTD.
 * It POWERS ACTD by evaluating decision quality across all generated drills.
 *
 * The doctrine is scenario-agnostic and transfers across:
 *   unauthorized access | suspicious object | escalating behavior |
 *   coworker concern | visitor management | environmental anomaly |
 *   threatening communication | emergency access violations
 *
 * The scenario changes. The decision doctrine does not.
 */

// ─── Core Principle Types ──────────────────────────────────────────────────────

export type DoctrinePrinciple =
  | "preserve_life_reduce_exposure"
  | "maintain_control_of_space"
  | "lowest_force_effective_response"
  | "activate_coordination_early"
  | "create_defensible_record";

export type DecisionEffect = "positive" | "neutral" | "negative";

/**
 * Five-dimension evaluation object stored on every generated response option.
 * This is computed BEFORE labels, outcomes, and expert reasoning are written.
 */
export type DecisionDoctrineEvaluation = {
  /** Principle 1: Does this action reduce immediate personal or group exposure? */
  exposure_effect: DecisionEffect;
  /** Principle 2: Does this action restore or preserve control of the environment? */
  control_effect: DecisionEffect;
  /** Principle 3: Does this action avoid unnecessary escalation or provocation? */
  escalation_effect: DecisionEffect;
  /** Principle 4: Does this action activate support or resources early? */
  coordination_effect: DecisionEffect;
  /** Principle 5: Does this action improve the ability to record and defend later? */
  documentation_effect: DecisionEffect;
  /** Optional analyst notes explaining non-obvious evaluations */
  notes?: string[];
};

