// ─── Cross-Scenario Transferability ───────────────────────────────────────────

export type DoctrineScenarioType =
  | "unauthorized_access"
  | "suspicious_object"
  | "escalating_behavior"
  | "coworker_concern"
  | "visitor_management"
  | "environmental_anomaly"
  | "threatening_communication"
  | "emergency_access_violation";

/**
 * All eight scenario types this doctrine applies to.
 * The scenario changes. The doctrine does not.
 */
export const DOCTRINE_SCENARIO_TYPES: DoctrineScenarioType[] = [
  "unauthorized_access",
  "suspicious_object",
  "escalating_behavior",
  "coworker_concern",
  "visitor_management",
  "environmental_anomaly",
  "threatening_communication",
  "emergency_access_violation",
];

// ─── Generated Option Shape ────────────────────────────────────────────────────

/**
 * Full shape of a doctrine-evaluated response option.
 * The doctrine_evaluation is computed first; all other fields derive from it.
 */
export type GeneratedOption = {
  id: string;
  label: string;
  description: string;
  doctrine_evaluation: DecisionDoctrineEvaluation;
  outcome_summary?: string;
  tradeoff_summary?: string;
  expert_reasoning?: string;
};

// ─── Drill Scenario Shape ──────────────────────────────────────────────────────

export type DrillScenario = {
  id: string;
  title: string;
  drill_type: "micro" | "guided" | "operational" | "extended";
  primary_threat_signal: string;
  decision_pressure: string[];
  options?: GeneratedOption[];
};

// ─── Viability Standards ───────────────────────────────────────────────────────

/**
 * Four real-world viability tests every generated option must pass.
 * If an option fails any test, it must not be generated.
 */
export const OPTION_VIABILITY_STANDARDS = {
  policy_alignment: "Must reflect realistic workplace protocols (corporate, healthcare, or public safety). No actions that violate standard guidelines.",
  role_appropriateness: "Must match the authority and training level of the role described. An employee does not physically restrain; security does not abandon post without protocol.",
  escalation_awareness: "Must consider how the individual may react: comply, evade, hesitate, or escalate.",
  no_theatrical_actions: "No yelling unnecessarily, dramatic confrontation, or exaggerated behaviors. Actions must be practical, controlled, and defensible in a real training program.",
} as const;
